# good: keep waiting until one succeeds (or all fail)
success = None
while tasks:
    done, pending = await asyncio.wait(tasks, return_when=asyncio.FIRST_COMPLETED)
    for t in done:
        try:
            success = t.result()
            break
        except Exception:
            pass
    if success is not None:
        break
    tasks = list(pending)

